<?php require_once 'functions.php'; require_once 'data/articles.php'; layout_header('Поиск'); $q=mb_strtolower(trim($_GET['q'] ?? '')); ?>
<h1>Поиск по сайту</h1><form class="wide-search" method="get"><input name="q" value="<?=htmlspecialchars($q)?>" placeholder="Введите запрос"><button class="btn">Искать</button></form>
<?php if($q===''): ?><p>Введите запрос для поиска.</p><?php else: ?><h2>Результаты по запросу «<?=htmlspecialchars($q)?>»</h2><div class="cards"><?php $found=0; foreach($articles as $a){ $hay=mb_strtolower($a['title'].' '.$a['category'].' '.$a['text']); if(mb_strpos($hay,$q)!==false){ article_card($a); $found++; }} foreach($products as $p){ $hay=mb_strtolower($p['name'].' '.$p['desc']); if(mb_strpos($hay,$q)!==false){ echo '<article class="card"><h3>'.htmlspecialchars($p['name']).'</h3><p>'.htmlspecialchars($p['desc']).'</p><p><strong>'.htmlspecialchars($p['price']).'</strong></p></article>'; $found++; }} if(!$found) echo '<p>Ничего не найдено.</p>'; ?></div><?php endif; ?>
<?php layout_footer(); ?>